#include<bits/stdc++.h>
using namespace std;
const long long mod=998244353;
bool vis[500010];
long long ans[500010];
long long n,k,a[500010];
vector<long long> mp[500010];
struct node
{
    long long x,step;
};
void bfs(long long s)
{
    queue<node> q;
    q.push((node){s,0});
    vis[s]=true;
    while(!q.empty())
    {
        long long t=q.front().x,p=q.front().step;
        if(p>k)
        {
            return;
        }
        q.pop();
        for(long long i:mp[t])
        {
            ans[i]+=(k-p)%mod;
            ans[i]%=mod;
            if(!vis[i])
            {
                vis[i]=true;
                ans[i]=(ans[i]+((__int128)a[i]*(k-p)%mod))%mod;
                q.push((node){i,p+1});
            }
        }
    }
}
int main()
{
    scanf("%lld%lld",&n,&k);
    for(long long i=0;i<=n;i++)
    {
        scanf("%lld",&a[i]);
        for(long long j=1;j<=a[i];j++)
        {
            long long x;
            scanf("%lld",&x);
            mp[i].push_back(x);
        }
    }
    bfs(0);
    for(long long i=1;i<=n;i++)
    {
        printf("%lld ",ans[i]);
    }
    return 0;
}
